import math

PI = 3.1415926535


def realcompare(a: float, b: float) -> str:
    """Compare two real numbers with respect to the six most significant digits.
    Returns 'LT' if a < b, 'EQ' if a = b, or 'GT' if a > b."""
    if a == 0.0 and b == 0.0:
        return "EQ"
    if a == 0.0:
        # Round b to 6 significant digits; if it rounds to 0, they're equal
        rb = round(b, -int(math.floor(math.log10(abs(b)))) + 5)
        if rb == 0.0:
            return "EQ"
        return "LT" if b > 0 else "GT"
    if b == 0.0:
        ra = round(a, -int(math.floor(math.log10(abs(a)))) + 5)
        if ra == 0.0:
            return "EQ"
        return "GT" if a > 0 else "LT"
    # Round both to 6 significant digits
    ra = round(a, -int(math.floor(math.log10(abs(a)))) + 5)
    rb = round(b, -int(math.floor(math.log10(abs(b)))) + 5)
    if ra < rb:
        return "LT"
    elif ra > rb:
        return "GT"
    else:
        return "EQ"


def _dist(x1, y1, x2, y2):
    """Euclidean distance between two points."""
    return math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2)


def _triangle_area(x1, y1, x2, y2, x3, y3):
    """Area of triangle formed by three points (using cross product / 2)."""
    return abs((x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1)) / 2.0


def _angle(x1, y1, x2, y2, x3, y3):
    """Angle at vertex (x2, y2) formed by points (x1,y1)-(x2,y2)-(x3,y3).
    Returns the angle in radians, or None if undefined (coincident points)."""
    dx1 = x1 - x2
    dy1 = y1 - y2
    dx3 = x3 - x2
    dy3 = y3 - y2
    len1 = math.sqrt(dx1 * dx1 + dy1 * dy1)
    len3 = math.sqrt(dx3 * dx3 + dy3 * dy3)
    if realcompare(len1, 0.0) == "EQ" or realcompare(len3, 0.0) == "EQ":
        return None
    cos_angle = (dx1 * dx3 + dy1 * dy3) / (len1 * len3)
    # Clamp to [-1, 1] to handle floating point errors
    cos_angle = max(-1.0, min(1.0, cos_angle))
    return math.acos(cos_angle)


def _circumradius(x1, y1, x2, y2, x3, y3):
    """Minimum enclosing circle radius for three points."""
    # Distances between each pair
    a = _dist(x1, y1, x2, y2)
    b = _dist(x2, y2, x3, y3)
    c = _dist(x1, y1, x3, y3)

    # If all three points coincide, radius is 0
    if realcompare(a, 0.0) == "EQ" and realcompare(b, 0.0) == "EQ":
        return 0.0

    # If two points coincide, the minimum enclosing circle has diameter = max edge
    if realcompare(a, 0.0) == "EQ":
        return b / 2.0
    if realcompare(b, 0.0) == "EQ":
        return c / 2.0  # max of a and c but a==c since b==0 means p2==p3
    if realcompare(c, 0.0) == "EQ":
        return a / 2.0

    # Sort sides so that sides[2] is the longest
    sides = sorted([a, b, c])

    # Check if the triangle is obtuse or right-angled:
    # If sides[2]^2 >= sides[0]^2 + sides[1]^2, the minimum enclosing circle
    # has the longest side as diameter.
    if realcompare(sides[2] * sides[2], sides[0] * sides[0] + sides[1] * sides[1]) != "LT":
        return sides[2] / 2.0

    # Acute triangle: use circumradius = abc / (4 * area)
    area = _triangle_area(x1, y1, x2, y2, x3, y3)
    if realcompare(area, 0.0) == "EQ":
        # Collinear: diameter is max distance
        return sides[2] / 2.0
    return (a * b * c) / (4.0 * area)


def _quadrant(px, py):
    """Determine quadrant of a point with priority I, II, III, IV.
    Quadrant I: x >= 0, y >= 0
    Quadrant II: x < 0, y >= 0
    Quadrant III: x < 0, y < 0 (also x <= 0, y < 0 after priority)
    Quadrant IV: x >= 0, y < 0 (but after priority, only x > 0, y < 0...
                  wait, let's follow the spec examples exactly)

    Per spec: (0,0)->I, (-1,0)->II, (0,-1)->III, (0,1)->I, (1,0)->I
    So priority means: if ambiguous, assign to lowest numbered quadrant.
    """
    if px >= 0 and py >= 0:
        return 1
    elif px < 0 and py >= 0:
        return 2
    elif px < 0 and py < 0:
        return 3
    else:  # px >= 0 and py < 0
        # (0, -1) should be quadrant III per spec example
        if px == 0:
            # Ambiguity: on negative y-axis, between III and IV.
            # Priority: III < IV, so assign III.
            return 3
        return 4


def _point_to_line_dist(px, py, x1, y1, x2, y2):
    """Distance from point (px,py) to the line defined by (x1,y1)-(x2,y2).
    If (x1,y1)==(x2,y2), returns distance from (px,py) to that point."""
    dx = x2 - x1
    dy = y2 - y1
    line_len = math.sqrt(dx * dx + dy * dy)
    if realcompare(line_len, 0.0) == "EQ":
        return _dist(px, py, x1, y1)
    return abs(dx * (y1 - py) - dy * (x1 - px)) / line_len


def _lic1(numpoints, x, y, parameters):
    """LIC 1: exists consecutive pair with distance > LENGTH1."""
    length1 = parameters['LENGTH1']
    for i in range(numpoints - 1):
        d = _dist(x[i], y[i], x[i + 1], y[i + 1])
        if realcompare(d, length1) == "GT":
            return True
    return False


def _lic2(numpoints, x, y, parameters):
    """LIC 2: exists consecutive triple that cannot be contained in circle of RADIUS1."""
    radius1 = parameters['RADIUS1']
    for i in range(numpoints - 2):
        r = _circumradius(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if realcompare(r, radius1) == "GT":
            return True
    return False


def _lic3(numpoints, x, y, parameters):
    """LIC 3: exists consecutive triple forming angle < PI-EPSILON or > PI+EPSILON."""
    epsilon = parameters['EPSILON']
    for i in range(numpoints - 2):
        ang = _angle(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if ang is None:
            continue
        if realcompare(ang, PI - epsilon) == "LT" or realcompare(ang, PI + epsilon) == "GT":
            return True
    return False


def _lic4(numpoints, x, y, parameters):
    """LIC 4: exists consecutive triple forming triangle with area > AREA1."""
    area1 = parameters['AREA1']
    for i in range(numpoints - 2):
        area = _triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if realcompare(area, area1) == "GT":
            return True
    return False


def _lic5(numpoints, x, y, parameters):
    """LIC 5: exists Q_PTS consecutive points in more than QUADS quadrants."""
    q_pts = parameters['Q_PTS']
    quads = parameters['QUADS']
    for i in range(numpoints - q_pts + 1):
        quadrant_set = set()
        for j in range(i, i + q_pts):
            quadrant_set.add(_quadrant(x[j], y[j]))
        if len(quadrant_set) > quads:
            return True
    return False


def _lic6(numpoints, x, y, parameters):
    """LIC 6: exists consecutive pair where X[j] - X[i] < 0 (j = i+1)."""
    for i in range(numpoints - 1):
        if realcompare(x[i + 1] - x[i], 0.0) == "LT":
            return True
    return False


def _lic7(numpoints, x, y, parameters):
    """LIC 7: exists N_PTS consecutive points where at least one point is
    distance > DIST from line joining first and last. Not met when NUMPOINTS < 3."""
    if numpoints < 3:
        return False
    n_pts = parameters['N_PTS']
    dist_param = parameters['DIST']
    for i in range(numpoints - n_pts + 1):
        last = i + n_pts - 1
        x1, y1 = x[i], y[i]
        x2, y2 = x[last], y[last]
        for j in range(i + 1, last):
            if realcompare(_dist(x1, y1, x2, y2), 0.0) == "EQ":
                d = _dist(x[j], y[j], x1, y1)
            else:
                d = _point_to_line_dist(x[j], y[j], x1, y1, x2, y2)
            if realcompare(d, dist_param) == "GT":
                return True
    return False


def _lic8(numpoints, x, y, parameters):
    """LIC 8: exists two points separated by exactly K_PTS intervening points
    with distance > LENGTH1. Not met when NUMPOINTS < 3."""
    if numpoints < 3:
        return False
    k_pts = parameters['K_PTS']
    length1 = parameters['LENGTH1']
    for i in range(numpoints - k_pts - 1):
        j = i + k_pts + 1
        d = _dist(x[i], y[i], x[j], y[j])
        if realcompare(d, length1) == "GT":
            return True
    return False


def _lic9(numpoints, x, y, parameters):
    """LIC 9: exists three points separated by A_PTS and B_PTS intervening points
    that cannot be contained in circle of RADIUS1. Not met when NUMPOINTS < 5."""
    if numpoints < 5:
        return False
    a_pts = parameters['A_PTS']
    b_pts = parameters['B_PTS']
    radius1 = parameters['RADIUS1']
    for i in range(numpoints - a_pts - b_pts - 2):
        j = i + a_pts + 1
        k = j + b_pts + 1
        r = _circumradius(x[i], y[i], x[j], y[j], x[k], y[k])
        if realcompare(r, radius1) == "GT":
            return True
    return False


def _lic10(numpoints, x, y, parameters):
    """LIC 10: exists three points separated by C_PTS and D_PTS intervening points
    forming angle < PI-EPSILON or > PI+EPSILON. Not met when NUMPOINTS < 5."""
    if numpoints < 5:
        return False
    c_pts = parameters['C_PTS']
    d_pts = parameters['D_PTS']
    epsilon = parameters['EPSILON']
    for i in range(numpoints - c_pts - d_pts - 2):
        j = i + c_pts + 1
        k = j + d_pts + 1
        ang = _angle(x[i], y[i], x[j], y[j], x[k], y[k])
        if ang is None:
            continue
        if realcompare(ang, PI - epsilon) == "LT" or realcompare(ang, PI + epsilon) == "GT":
            return True
    return False


def _lic11(numpoints, x, y, parameters):
    """LIC 11: exists three points separated by E_PTS and F_PTS intervening points
    forming triangle with area > AREA1. Not met when NUMPOINTS < 5."""
    if numpoints < 5:
        return False
    e_pts = parameters['E_PTS']
    f_pts = parameters['F_PTS']
    area1 = parameters['AREA1']
    for i in range(numpoints - e_pts - f_pts - 2):
        j = i + e_pts + 1
        k = j + f_pts + 1
        area = _triangle_area(x[i], y[i], x[j], y[j], x[k], y[k])
        if realcompare(area, area1) == "GT":
            return True
    return False


def _lic12(numpoints, x, y, parameters):
    """LIC 12: exists two points separated by G_PTS intervening points where
    X[j] - X[i] < 0. Not met when NUMPOINTS < 3."""
    if numpoints < 3:
        return False
    g_pts = parameters['G_PTS']
    for i in range(numpoints - g_pts - 1):
        j = i + g_pts + 1
        if realcompare(x[j] - x[i], 0.0) == "LT":
            return True
    return False


def _lic13(numpoints, x, y, parameters):
    """LIC 13: Both conditions must be true:
    1) exists two points separated by K_PTS with distance > LENGTH1
    2) exists two points separated by K_PTS with distance < LENGTH2
    Not met when NUMPOINTS < 3."""
    if numpoints < 3:
        return False
    k_pts = parameters['K_PTS']
    length1 = parameters['LENGTH1']
    length2 = parameters['LENGTH2']
    cond1 = False
    cond2 = False
    for i in range(numpoints - k_pts - 1):
        j = i + k_pts + 1
        d = _dist(x[i], y[i], x[j], y[j])
        if realcompare(d, length1) == "GT":
            cond1 = True
        if realcompare(d, length2) == "LT":
            cond2 = True
        if cond1 and cond2:
            return True
    return cond1 and cond2


def _lic14(numpoints, x, y, parameters):
    """LIC 14: Both conditions must be true:
    1) exists three points separated by A_PTS, B_PTS that cannot fit in circle of RADIUS1
    2) exists three points separated by A_PTS, B_PTS that can fit in circle of RADIUS2
    Not met when NUMPOINTS < 5."""
    if numpoints < 5:
        return False
    a_pts = parameters['A_PTS']
    b_pts = parameters['B_PTS']
    radius1 = parameters['RADIUS1']
    radius2 = parameters['RADIUS2']
    cond1 = False
    cond2 = False
    for i in range(numpoints - a_pts - b_pts - 2):
        j = i + a_pts + 1
        k = j + b_pts + 1
        r = _circumradius(x[i], y[i], x[j], y[j], x[k], y[k])
        if realcompare(r, radius1) == "GT":
            cond1 = True
        if realcompare(r, radius2) != "GT":
            cond2 = True
        if cond1 and cond2:
            return True
    return cond1 and cond2


def _lic15(numpoints, x, y, parameters):
    """LIC 15: Both conditions must be true:
    1) exists three points separated by E_PTS, F_PTS forming triangle with area > AREA1
    2) exists three points separated by E_PTS, F_PTS forming triangle with area < AREA2
    Not met when NUMPOINTS < 5."""
    if numpoints < 5:
        return False
    e_pts = parameters['E_PTS']
    f_pts = parameters['F_PTS']
    area1 = parameters['AREA1']
    area2 = parameters['AREA2']
    cond1 = False
    cond2 = False
    for i in range(numpoints - e_pts - f_pts - 2):
        j = i + e_pts + 1
        k = j + f_pts + 1
        area = _triangle_area(x[i], y[i], x[j], y[j], x[k], y[k])
        if realcompare(area, area1) == "GT":
            cond1 = True
        if realcompare(area, area2) == "LT":
            cond2 = True
        if cond1 and cond2:
            return True
    return cond1 and cond2


def decide(numpoints, x, y, parameters, lcm, pum_diag):
    """Behaviorally equivalent to the DECIDE procedure from the spec.

    Returns (cmv, pum, fuv, launch).
    """
    # --- CMV ---
    lic_funcs = [
        _lic1, _lic2, _lic3, _lic4, _lic5,
        _lic6, _lic7, _lic8, _lic9, _lic10,
        _lic11, _lic12, _lic13, _lic14, _lic15,
    ]
    cmv = [func(numpoints, x, y, parameters) for func in lic_funcs]

    # --- PUM ---
    pum = [[False] * 15 for _ in range(15)]
    for i in range(15):
        pum[i][i] = pum_diag[i]
        for j in range(15):
            if i == j:
                continue
            connector = lcm[i][j]
            if connector == "NOTUSED":
                pum[i][j] = True
            elif connector == "ANDD":
                pum[i][j] = cmv[i] and cmv[j]
            elif connector == "ORR":
                pum[i][j] = cmv[i] or cmv[j]

    # --- FUV ---
    fuv = [False] * 15
    for i in range(15):
        if not pum[i][i]:
            # PUM[i,i] is false => LIC should not hold back launch
            fuv[i] = True
        else:
            # Check if all elements in row i are true
            fuv[i] = all(pum[i][j] for j in range(15))

    # --- LAUNCH ---
    launch = all(fuv)

    return (cmv, pum, fuv, launch)
